import { merge } from '../merge/index.js';
import { sleep } from '../sleep/index.js';
import { trampoline } from '../trampoline/index.js';

const defaults = {
  retry: 3,
  retryDelay: 500,
  retryDelayFactor: 2
};
const withRetry = (func, options) => {
  const { onError, retry, retryDelay, retryDelayFactor, retryDelayMax } = merge(defaults, options);
  const withRetryInternal = async (retryCount, ...args) => {
    try {
      return await func(...args);
    } catch (err) {
      onError?.(err);
      if (retryCount >= retry)
        throw err;
      await sleep(
        retryDelayMax == null ? retryDelay : Math.min(retryDelay * retryDelayFactor ** retryCount, retryDelayMax)
      );
      return async () => withRetryInternal(retryCount + 1, ...args);
    }
  };
  return async (...args) => trampoline(async () => withRetryInternal(0, ...args));
};

export { withRetry };
